const items = $input.all();
const competitor_jobs = (items[0]?.json?.data || []);
const role_jobs = (items[1]?.json?.data || []);

// Competitor analysis
const byCompany = {};
competitor_jobs.forEach(j => {
  const co = j.employer_name || 'Unknown';
  if (!byCompany[co]) byCompany[co] = { company: co, total: 0, by_dept: {} };
  byCompany[co].total++;
  const dept = j.job_title?.toLowerCase().includes('engineer') ? 'Engineering'
    : j.job_title?.toLowerCase().includes('sales') ? 'Sales'
    : j.job_title?.toLowerCase().includes('market') ? 'Marketing'
    : j.job_title?.toLowerCase().includes('data') ? 'Data/Analytics'
    : 'Other';
  byCompany[co].by_dept[dept] = (byCompany[co].by_dept[dept] || 0) + 1;
});
const competitor_summary = Object.values(byCompany).sort((a,b) => b.total-a.total);

// Skill demand analysis
const SKILLS_TAXONOMY = ['Python','SQL','React','TypeScript','Kubernetes','AWS','Terraform','dbt','Looker','HubSpot','Salesforce','n8n','Zapier','GPT','LLM','AI','Machine Learning','Analytics','Tableau','Power BI'];
const skill_counts = {};
role_jobs.forEach(j => {
  const desc = (j.job_description || '').toLowerCase();
  SKILLS_TAXONOMY.forEach(skill => {
    if (desc.includes(skill.toLowerCase())) skill_counts[skill] = (skill_counts[skill]||0)+1;
  });
});
const skill_demand = Object.entries(skill_counts).sort((a,b) => b[1]-a[1]).slice(0,15).map(([k,v]) => ({skill: k, count: v, pct: Math.round(v/role_jobs.length*100)}));

return [{ json: { competitor_summary, skill_demand, competitor_total: competitor_jobs.length, role_jobs_analysed: role_jobs.length, month: new Date().toLocaleDateString('en-GB',{month:'long',year:'numeric'}) } }];

